packages/utils/src/index.ts:
export function cn(...classes: (string|undefined|null|false)[]) {
  return classes.filter(Boolean).join(' ')
}
export const ok  = <T>(data: T)  => ({ data, error: null, success: true })
export const err = (msg: string) => ({ data: null, error: msg, success: false })

export function formatCurrency(n: number, currency = 'USD') {
  return new Intl.NumberFormat('en-US',{style:'currency',currency}).format(n)
}
export function formatPct(n: number, d = 2) {
  return `${n >= 0 ? '+' : ''}${n.toFixed(d)}%`
}
export function formatDuration(s: number) {
  const h = Math.floor(s/3600), m = Math.floor((s%3600)/60), sec = s%60
  if (h > 0) return `${h}:${String(m).padStart(2,'0')}:${String(sec).padStart(2,'0')}`
  return `${m}:${String(sec).padStart(2,'0')}`
}
export function slugify(str: string) {
  return str.toLowerCase().replace(/[^\w\s-]/g,'').replace(/[\s_-]+/g,'-').replace(/^-+|-+$/g,'')
}
export function getInitials(name: string) {
  return name.split(' ').map(n => n[0]).join('').toUpperCase().slice(0,2)
}
export function relativeTime(dateStr: string) {
  const diff = Math.floor((Date.now() - new Date(dateStr).getTime()) / 1000)
  if (diff < 60)    return 'just now'
  if (diff < 3600)  return `${Math.floor(diff/60)}m ago`
  if (diff < 86400) return `${Math.floor(diff/3600)}h ago`
  return `${Math.floor(diff/86400)}d ago`
}
export const pnlColor = (v: number) =>
  v > 0 ? 'text-emerald-400' : v < 0 ? 'text-red-400' : 'text-zinc-400'

export function generateInvoiceNumber() {
  return `INV-${new Date().getFullYear()}-${String(Math.floor(Math.random()*9000)+1000)}`
}

