'use client'
import { useEffect } from 'react'
import { cn } from '@jaup/utils'
interface Props{open:boolean;onClose():void;title?:string;children:React.ReactNode;size?:'sm'|'md'|'lg'}
const SZ={sm:'max-w-sm',md:'max-w-lg',lg:'max-w-2xl'}
export function Modal({open,onClose,title,children,size='md'}:Props){
  useEffect(()=>{
    const h=(e:KeyboardEvent)=>{ if(e.key==='Escape') onClose() }
    document.addEventListener('keydown',h)
    return()=>document.removeEventListener('keydown',h)
  },[onClose])
  if(!open) return null
  return(
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/70 backdrop-blur-sm" onClick={onClose}/>
      <div className={cn('relative bg-zinc-900 border border-zinc-700 rounded-2xl w-full shadow-2xl',SZ[size])}>
        {title&&(
          <div className="flex items-center justify-between px-6 py-4 border-b border-zinc-800">
            <h2 className="text-lg font-semibold text-white">{title}</h2>
            <button onClick={onClose} className="text-zinc-500 hover:text-white transition-colors">✕</button>
          </div>
        )}
        <div className="p-6">{children}</div>
      </div>
    </div>
  )
}

