'use client'
import{useEffect,useState}from'react'
export default function Page(){
  const[items,setItems]=useState<any[]>([])
  const[loading,setLoading]=useState(true)
  const[show,setShow]=useState(false)
  const[form,setForm]=useState<Record<string,string>>({})
  const ic="w-full bg-zinc-800 border border-zinc-700 rounded-lg px-3 py-2 text-sm text-zinc-100 placeholder-zinc-500 focus:outline-none focus:ring-2 focus:ring-violet-500"
  async function load(){setLoading(true);const r=await fetch('/api/copilot_tasks').then(r=>r.json());setItems(r.data??[]);setLoading(false)}
  useEffect(()=>{load()},[])
  async function save(e:React.FormEvent){e.preventDefault();await fetch('/api/copilot_tasks',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(form)});setShow(false);setForm({});load()}
  async function del(id:string){await fetch(`/api/copilot_tasks/${id}`,{method:'DELETE'});load()}
  return(
    <div className="min-h-screen bg-zinc-950 text-zinc-100">
      <div className="sticky top-0 z-30 bg-zinc-900/80 backdrop-blur border-b border-zinc-800">
        <div className="max-w-5xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3"><a href="/dashboard" className="text-zinc-500 hover:text-white text-sm">← Hub</a><span className="text-zinc-700">|</span><span className="text-xl">🔑</span><h1 className="font-bold text-white">Password Vault</h1><span className="text-xs bg-zinc-800 text-zinc-400 px-2 py-0.5 rounded-full">{items.length}</span></div>
          <button onClick={()=>setShow(!show)} className="bg-violet-600 hover:bg-violet-500 text-white text-sm font-medium px-4 py-2 rounded-lg">+ Add</button>
        </div>
      </div>
      <div className="max-w-5xl mx-auto px-4 py-8 space-y-4">
        {show&&(<form onSubmit={save} className="bg-zinc-900 border border-violet-800/40 rounded-2xl p-6 space-y-3"><div className="grid grid-cols-2 gap-3"><input className={ic} placeholder="Name / Title *" required value={form.title||form.name||''} onChange={e=>setForm({...form,title:e.target.value,name:e.target.value})} /><input className={ic} placeholder="Description" value={form.description||''} onChange={e=>setForm({...form,description:e.target.value})}/></div><div className="flex gap-2"><button type="submit" className="bg-violet-600 hover:bg-violet-500 text-white text-sm px-4 py-2 rounded-lg">Save</button><button type="button" onClick={()=>setShow(false)} className="text-zinc-400 text-sm px-4 py-2 rounded-lg hover:bg-zinc-800">Cancel</button></div></form>)}
        {loading?<div className="text-center py-16 text-zinc-500">Loading…</div>:items.length===0?(<div className="text-center py-16"><div className="text-5xl mb-4">🔑</div><p className="text-zinc-500">No entries yet.</p></div>):(
          <div className="space-y-2">{items.map((it:any)=>(<div key={it.id} className="bg-zinc-900 border border-zinc-800 hover:border-zinc-700 rounded-xl px-5 py-4 flex items-center gap-4 group transition-all"><span className="text-2xl flex-shrink-0">🔑</span><div className="flex-1 min-w-0"><p className="font-medium text-zinc-100 text-sm truncate">{it.title||it.name||it.full_name||it.description||it.symbol||'Entry'}</p><p className="text-xs text-zinc-500">{new Date(it.created_at).toLocaleDateString()}</p></div><button onClick={()=>del(it.id)} className="text-zinc-600 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-all">×</button></div>))}</div>
        )}
      </div>
    </div>
  )
}

