export async function GET(){const user=await authedUser();if(!user)return NextResponse.json({error:'Unauthorized'},{status:401});const{data,error}=await serverClient().from('copilot_tasks').select('*').eq('user_id',user.id).order('created_at',{ascending:false});if(error)return NextResponse.json({error:error.message},{status:500});return NextResponse.json({data})}
export async function POST(req:NextRequest){const user=await authedUser();if(!user)return NextResponse.json({error:'Unauthorized'},{status:401});const body=await req.json();const{data,error}=await serverClient().from('copilot_tasks').insert({...body,user_id:user.id}).select().single();if(error)return NextResponse.json({error:error.message},{status:500});return NextResponse.json({data},{status:201})}

import{serverClient,authedUser}from'@/lib/supabase-server'
import{NextRequest,NextResponse}from'next/server'
export async function PATCH(req:NextRequest,{params}:{params:{id:string}}){const user=await authedUser();if(!user)return NextResponse.json({error:'Unauthorized'},{status:401});const body=await req.json();const{data,error}=await serverClient().from('copilot_tasks').update(body).eq('id',params.id).eq('user_id',user.id).select().single();if(error)return NextResponse.json({error:error.message},{status:500});return NextResponse.json({data})}
export async function DELETE(_:NextRequest,{params}:{params:{id:string}}){const user=await authedUser();if(!user)return NextResponse.json({error:'Unauthorized'},{status:401});const{error}=await serverClient().from('copilot_tasks').delete().eq('id',params.id).eq('user_id',user.id);if(error)return NextResponse.json({error:error.message},{status:500});return NextResponse.json({success:true})}

