'use client'
import{useEffect,useState}from'react'
const PC2:Record<string,string>={low:'bg-zinc-700 text-zinc-400',medium:'bg-blue-900/40 text-blue-400',high:'bg-amber-900/40 text-amber-400',critical:'bg-red-900/40 text-red-400'}
const SC2:Record<string,string>={todo:'bg-zinc-700 text-zinc-400',in_progress:'bg-violet-900/40 text-violet-400',blocked:'bg-red-900/40 text-red-400',done:'bg-emerald-900/40 text-emerald-400'}
export default function CopilotTasks(){
  const[tasks,setTasks]=useState<any[]>([])
  const[loading,setLoading]=useState(true)
  const[show,setShow]=useState(false)
  const[filter,setFilter]=useState('all')
  const[form,setForm]=useState<Record<string,string>>({})
  const ic="w-full bg-zinc-800 border border-zinc-700 rounded-lg px-3 py-2 text-sm text-zinc-100 placeholder-zinc-500 focus:outline-none focus:ring-2 focus:ring-violet-500"
  async function load(){setLoading(true);const r=await fetch('/api/tasks').then(r=>r.json());setTasks(r.data??[]);setLoading(false)}
  useEffect(()=>{load()},[])
  async function create(e:React.FormEvent){e.preventDefault();await fetch('/api/tasks',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({title:form.title,description:form.desc||null,priority:form.priority||'medium',status:'todo',due_date:form.due||null,tags:[]})});setShow(false);setForm({});load()}
  async function setStatus(id:string,status:string){await fetch(`/api/tasks/${id}`,{method:'PATCH',headers:{'Content-Type':'application/json'},body:JSON.stringify({status})});load()}
  async function del(id:string){await fetch(`/api/tasks/${id}`,{method:'DELETE'});load()}
  const counts={todo:tasks.filter(t=>t.status==='todo').length,in_progress:tasks.filter(t=>t.status==='in_progress').length,blocked:tasks.filter(t=>t.status==='blocked').length,done:tasks.filter(t=>t.status==='done').length}
  const filtered=filter==='all'?tasks:tasks.filter(t=>t.status===filter)
  return(
    <div className="min-h-screen bg-zinc-950 text-zinc-100">
      <div className="sticky top-0 z-30 bg-zinc-900/80 backdrop-blur border-b border-zinc-800">
        <div className="max-w-5xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3"><a href="/dashboard" className="text-zinc-500 hover:text-white text-sm">← Hub</a><span className="text-zinc-700">|</span><span>🤖</span><h1 className="font-bold text-white">Copilot Tasks</h1></div>
          <button onClick={()=>setShow(!show)} className="bg-violet-600 hover:bg-violet-500 text-white text-sm font-medium px-4 py-2 rounded-lg">+ Task</button>
        </div>
      </div>
      <div className="max-w-5xl mx-auto px-4 py-8 space-y-6">
        <div className="grid grid-cols-4 gap-3">{[{l:'To Do',k:'todo',i:'⬜',c:'text-zinc-300'},{l:'In Progress',k:'in_progress',i:'🔄',c:'text-violet-400'},{l:'Blocked',k:'blocked',i:'🚫',c:'text-red-400'},{l:'Done',k:'done',i:'✅',c:'text-emerald-400'}].map(s=><button key={s.k} onClick={()=>setFilter(filter===s.k?'all':s.k)} className={`bg-zinc-900 border rounded-xl p-4 text-left transition-all ${filter===s.k?'border-violet-500':'border-zinc-800 hover:border-zinc-700'}`}><div className="text-xl mb-1">{s.i}</div><div className={`text-2xl font-bold ${s.c}`}>{counts[s.k as keyof typeof counts]}</div><div className="text-xs text-zinc-500">{s.l}</div></button>)}</div>
        {tasks.length>0&&<div><div className="flex justify-between text-xs text-zinc-500 mb-1.5"><span>Completion</span><span>{counts.done}/{tasks.length}</span></div><div className="h-2 bg-zinc-800 rounded-full overflow-hidden"><div className="h-full bg-gradient-to-r from-violet-600 to-emerald-500 rounded-full transition-all" style={{width:`${tasks.length?Math.round(counts.done/tasks.length*100):0}%`}}/></div></div>}
        {show&&<form onSubmit={create} className="bg-zinc-900 border border-violet-800/40 rounded-2xl p-6 space-y-3"><h3 className="font-semibold text-white text-sm">New Task</h3><div className="grid grid-cols-2 sm:grid-cols-4 gap-3"><div className="col-span-2"><input className={ic} placeholder="Title *" required value={form.title||''} onChange={e=>setForm({...form,title:e.target.value})}/></div><select className={ic} value={form.priority||'medium'} onChange={e=>setForm({...form,priority:e.target.value})}><option value="low">Low</option><option value="medium">Medium</option><option value="high">High</option><option value="critical">Critical</option></select><input className={ic} type="date" value={form.due||''} onChange={e=>setForm({...form,due:e.target.value})}/></div><textarea className={`${ic} resize-none`} rows={2} placeholder="Description" value={form.desc||''} onChange={e=>setForm({...form,desc:e.target.value})}/><div className="flex gap-2"><button type="submit" className="bg-violet-600 hover:bg-violet-500 text-white text-sm px-4 py-2 rounded-lg">Create</button><button type="button" onClick={()=>setShow(false)} className="text-zinc-400 text-sm px-4 py-2 rounded-lg hover:bg-zinc-800">Cancel</button></div></form>}
        {loading?<div className="text-center py-16 text-zinc-500">Loading…</div>:filtered.length===0?<div className="text-center py-16"><div className="text-5xl mb-4">🤖</div><p className="text-zinc-500">No tasks yet.</p></div>:(
          <div className="space-y-2">{filtered.map((t:any)=><div key={t.id} className={`bg-zinc-900 border rounded-xl px-5 py-4 flex items-start gap-4 group transition-all ${t.status==='done'?'border-zinc-800 opacity-60':'border-zinc-800 hover:border-zinc-700'}`}><button onClick={()=>setStatus(t.id,t.status==='done'?'todo':'done')} className={`mt-0.5 w-5 h-5 rounded-full border-2 flex-shrink-0 flex items-center justify-center transition-all ${t.status==='done'?'bg-emerald-500 border-emerald-500':'border-zinc-600 hover:border-violet-400'}`}>{t.status==='done'&&<span className="text-white text-xs">✓</span>}</button><div className="flex-1 min-w-0"><div className="flex items-center gap-2 flex-wrap"><span className={`font-medium text-sm ${t.status==='done'?'line-through text-zinc-500':'text-zinc-100'}`}>{t.title}</span><span className={`text-xs px-2 py-0.5 rounded-md ${PC2[t.priority]}`}>{t.priority}</span><span className={`text-xs px-2 py-0.5 rounded-md ${SC2[t.status]}`}>{t.status.replace('_',' ')}</span>{t.due_date&&<span className="text-xs text-zinc-500">📅 {t.due_date}</span>}</div>{t.description&&<p className="text-xs text-zinc-500 mt-1">{t.description}</p>}</div><div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">{t.status!=='in_progress'&&t.status!=='done'&&<button onClick={()=>setStatus(t.id,'in_progress')} className="text-xs text-zinc-400 hover:text-violet-400 px-2 py-1 rounded hover:bg-zinc-800">Start</button>}{t.status!=='blocked'&&t.status!=='done'&&<button onClick={()=>setStatus(t.id,'blocked')} className="text-xs text-zinc-400 hover:text-red-400 px-2 py-1 rounded hover:bg-zinc-800">Block</button>}<button onClick={()=>del(t.id)} className="text-xs text-zinc-500 hover:text-red-400 px-2 py-1 rounded hover:bg-zinc-800">×</button></div></div>)}</div>
        )}
      </div>
    </div>
  )
}

