import { redirect } from 'next/navigation'
import { getUser, createSupabaseServerClient } from '@/lib/supabase-server'
import { Navbar } from '@/components/Navbar'
import { AppCard } from '@/components/AppCard'
import type { AppMetadata } from '@jaup/types'
export const metadata = { title: 'Central Hub' }

const CATEGORIES = [
  { key:'music',       label:'🎵 Music & Media'    },
  { key:'finance',     label:'💰 Finance'           },
  { key:'crypto',      label:'🔐 Crypto & Web3'     },
  { key:'productivity',label:'⚙️ Productivity'      },
  { key:'ai',          label:'🤖 AI & Research'     },
  { key:'marketing',   label:'📱 Marketing'         },
  { key:'education',   label:'📚 Education'         },
  { key:'health',      label:'💪 Health & Wellness' },
  { key:'commerce',    label:'🛒 Commerce'          },
]

export default async function DashboardPage() {
  const session = await getUser()
  if (!session) redirect('/auth/login')
  const { profile } = session
  const sb = createSupabaseServerClient()
  const { data: apps } = await sb.from('app_registry').select('*').eq('is_active', true).order('sort_order')
  const list = (apps ?? []) as AppMetadata[]
  const featured = list.filter(a => ['music-studio','trading-forecasting','command-center','copilot-tasks','ai-writer','portfolio-tracker'].includes(a.id))

  return (
    <div className="min-h-screen bg-zinc-950">
      <Navbar profile={profile as any} />
      <main className="max-w-screen-2xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <div className="mb-10">
          <h1 className="text-3xl font-bold text-white">
            Welcome back, <span className="bg-gradient-to-r from-violet-400 to-pink-400 bg-clip-text text-transparent">{profile?.full_name?.split(' ')[0] ?? 'J-Roc'}</span> ⚡
          </h1>
          <p className="text-zinc-400 text-sm mt-1">Your J-Roc Apex Ultra Platform — {list.length} apps live.</p>
        </div>

        <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 mb-10">
          {[
            { label:'Total Apps',  value:list.length,                                      icon:'⚡', color:'text-violet-400' },
            { label:'Free Apps',   value:list.filter(a=>a.requires_plan==='free').length,  icon:'🆓', color:'text-emerald-400' },
            { label:'Pro Apps',    value:list.filter(a=>a.requires_plan==='pro').length,   icon:'💎', color:'text-blue-400' },
            { label:'Ultra Apps',  value:list.filter(a=>a.requires_plan==='ultra').length, icon:'🔱', color:'text-amber-400' },
          ].map(s=>(
            <div key={s.label} className="bg-zinc-900 border border-zinc-800 rounded-xl p-4">
              <div className="text-2xl mb-1">{s.icon}</div>
              <div className={`text-2xl font-bold ${s.color}`}>{s.value}</div>
              <div className="text-zinc-500 text-xs mt-0.5">{s.label}</div>
            </div>
          ))}
        </div>

        <section className="mb-10">
          <h2 className="text-xs font-semibold text-zinc-400 uppercase tracking-wider mb-4">🚀 Flagship Apps</h2>
          <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-6 gap-4">
            {featured.map(app => <AppCard key={app.id} app={app} featured />)}
          </div>
        </section>

        {CATEGORIES.map(cat => {
          const catApps = list.filter(a => a.category === cat.key)
          if (!catApps.length) return null
          return (
            <section key={cat.key} className="mb-10">
              <h2 className="text-xs font-semibold text-zinc-400 uppercase tracking-wider mb-4">{cat.label}</h2>
              <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-4">
                {catApps.map(app => <AppCard key={app.id} app={app} />)}
              </div>
            </section>
          )
        })}
      </main>
    </div>
  )
}

