'use client'
import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { getSupabaseBrowserClient } from '@/lib/supabase-browser'

export default function SignupPage() {
  const [email, setEmail]       = useState('')
  const [password, setPassword] = useState('')
  const [name, setName]         = useState('')
  const [loading, setLoading]   = useState(false)
  const [error, setError]       = useState<string|null>(null)
  const [done, setDone]         = useState(false)
  const router = useRouter()
  const sb     = getSupabaseBrowserClient()

  async function signup(e: React.FormEvent) {
    e.preventDefault(); setLoading(true); setError(null)
    const { error } = await sb.auth.signUp({ email, password, options: { data: { full_name: name } } })
    if (error) { setError(error.message); setLoading(false) } else setDone(true)
  }

  if (done) return (
    <div className="min-h-screen bg-zinc-950 flex items-center justify-center p-4">
      <div className="text-center max-w-md">
        <div className="text-6xl mb-4">📧</div>
        <h2 className="text-2xl font-bold text-white mb-2">Check your email</h2>
        <p className="text-zinc-400">Confirmation link sent to <strong className="text-violet-400">{email}</strong>.</p>
        <button onClick={()=>router.push('/auth/login')} className="mt-6 px-6 py-2.5 bg-violet-600 hover:bg-violet-500 text-white font-medium rounded-lg transition-all">Back to Login</button>
      </div>
    </div>
  )

  return (
    <div className="min-h-screen bg-zinc-950 flex items-center justify-center p-4">
      <div className="w-full max-w-md">
        <div className="text-center mb-8">
          <div className="inline-flex items-center justify-center w-16 h-16 rounded-2xl bg-violet-600 mb-4 text-3xl">⚡</div>
          <h1 className="text-3xl font-bold text-white">Join JAUP</h1>
        </div>
        <div className="bg-zinc-900 border border-zinc-800 rounded-2xl p-8">
          <form onSubmit={signup} className="space-y-4">
            {error && <div className="bg-red-900/30 border border-red-800 rounded-lg px-4 py-3 text-red-300 text-sm">{error}</div>}
            {[{label:'Full Name',type:'text',value:name,set:setName,placeholder:'J-Roc'},{label:'Email',type:'email',value:email,set:setEmail,placeholder:'jroc@jaup.io'},{label:'Password',type:'password',value:password,set:setPassword,placeholder:'Min 8 characters'}].map(f=>(
              <div key={f.label}>
                <label className="block text-xs text-zinc-400 mb-1.5">{f.label}</label>
                <input type={f.type} value={f.value} onChange={e=>f.set(e.target.value)} required placeholder={f.placeholder}
                  className="w-full bg-zinc-800 border border-zinc-700 rounded-lg px-3 py-2.5 text-sm text-zinc-100 placeholder-zinc-500 focus:outline-none focus:ring-2 focus:ring-violet-500"/>
              </div>
            ))}
            <button type="submit" disabled={loading} className="w-full bg-violet-600 hover:bg-violet-500 disabled:opacity-50 text-white font-semibold py-2.5 rounded-lg transition-all">
              {loading ? 'Creating…' : 'Create Account'}
