          <h1 className="text-3xl font-bold text-white">JAUP Platform</h1>
          <p className="text-zinc-400 mt-1 text-sm">J-Roc Apex Ultra Platform</p>
        </div>
        <div className="bg-zinc-900 border border-zinc-800 rounded-2xl p-8 shadow-2xl">
          <div className="grid grid-cols-2 gap-3 mb-6">
            <button onClick={()=>oauth('google')} className="flex items-center justify-center gap-2 px-4 py-2.5 rounded-lg bg-zinc-800 hover:bg-zinc-700 border border-zinc-700 text-sm text-zinc-200 transition-all">🌐 Google</button>
            <button onClick={()=>oauth('github')} className="flex items-center justify-center gap-2 px-4 py-2.5 rounded-lg bg-zinc-800 hover:bg-zinc-700 border border-zinc-700 text-sm text-zinc-200 transition-all">🐙 GitHub</button>
          </div>
          <div className="flex items-center gap-3 mb-6"><div className="flex-1 h-px bg-zinc-800"/><span className="text-xs text-zinc-500">or email</span><div className="flex-1 h-px bg-zinc-800"/></div>
          <form onSubmit={login} className="space-y-4">
            {error && <div className="bg-red-900/30 border border-red-800 rounded-lg px-4 py-3 text-red-300 text-sm">{error}</div>}
            <div>
              <label className="block text-xs text-zinc-400 mb-1.5">Email</label>
              <input type="email" value={email} onChange={e=>setEmail(e.target.value)} required placeholder="jroc@jaup.io"
                className="w-full bg-zinc-800 border border-zinc-700 rounded-lg px-3 py-2.5 text-sm text-zinc-100 placeholder-zinc-500 focus:outline-none focus:ring-2 focus:ring-violet-500"/>
            </div>
