    const ports=p.data??[];setPortfolios(ports);setPositions(pos.data??[]);setForecasts(fc.data??[])
    if(ports.length&&!selPort)setSelPort(ports[0]?.id)
    setLoading(false)
  }
  useEffect(()=>{load()},[])
  async function createPort(e:React.FormEvent){e.preventDefault();await fetch('/api/portfolios',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({name:form.pname,description:form.pdesc,cash_balance:parseFloat(form.cash||'0')})});setShowPortForm(false);setForm({});load()}
  async function createPos(e:React.FormEvent){e.preventDefault();await fetch('/api/positions',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({portfolio_id:selPort,symbol:form.sym?.toUpperCase(),asset_type:form.atype||'stock',quantity:parseFloat(form.qty||'0'),avg_cost:parseFloat(form.cost||'0'),current_price:parseFloat(form.price||'0'),pnl:(parseFloat(form.price||'0')-parseFloat(form.cost||'0'))*parseFloat(form.qty||'0')})});setShowPosForm(false);setForm({});load()}
  async function createFc(e:React.FormEvent){e.preventDefault();await fetch('/api/forecasts',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({symbol:form.fsym?.toUpperCase(),target_price:parseFloat(form.ftarget||'0'),prediction_date:form.fdate,confidence_score:parseFloat(form.fconf||'50'),model_used:form.fmodel||'manual',notes:form.fnotes||null})});setShowFcForm(false);setForm({});load()}
  const curPort=portfolios.find(p=>p.id===selPort)
  const filtPos=positions.filter(p=>p.portfolio_id===selPort)
  const totalPnL=filtPos.reduce((s,p)=>s+Number(p.pnl),0)
  return(
    <div className="min-h-screen bg-zinc-950 text-zinc-100">
      <div className="sticky top-0 z-30 bg-zinc-900/80 backdrop-blur border-b border-zinc-800">
        <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3"><a href="/dashboard" className="text-zinc-500 hover:text-white text-sm">← Hub</a><span className="text-zinc-700">|</span><span>📈</span><h1 className="font-bold text-white">Trading & Forecasting</h1></div>
          <div className="flex gap-2">
            <button onClick={()=>{setShowPortForm(!showPortForm);setShowPosForm(false);setShowFcForm(false)}} className="text-xs bg-zinc-800 hover:bg-zinc-700 border border-zinc-700 text-zinc-300 px-3 py-2 rounded-lg">+ Portfolio</button>
            <button onClick={()=>{setShowPosForm(!showPosForm);setShowPortForm(false);setShowFcForm(false)}} className="text-xs bg-violet-600 hover:bg-violet-500 text-white px-3 py-2 rounded-lg">+ Position</button>
            <button onClick={()=>{setShowFcForm(!showFcForm);setShowPortForm(false);setShowPosForm(false)}} className="text-xs bg-emerald-700 hover:bg-emerald-600 text-white px-3 py-2 rounded-lg">+ Forecast</button>
          </div>
        </div>
      </div>
      <div className="max-w-6xl mx-auto px-4 py-8 space-y-6">
        {portfolios.length>0&&<div className="flex gap-2 flex-wrap">{portfolios.map(p=><button key={p.id} onClick={()=>setSelPort(p.id)} className={`px-4 py-2 rounded-xl text-sm font-medium border transition-all ${selPort===p.id?'bg-violet-700 border-violet-600 text-white':'bg-zinc-900 border-zinc-800 text-zinc-400 hover:border-zinc-600'}`}>{p.name}</button>)}</div>}
        {curPort&&<div className="grid grid-cols-2 sm:grid-cols-4 gap-4">{[{l:'Cash',v:`$${Number(curPort.cash_balance).toLocaleString('en-US',{minimumFractionDigits:2})}`,i:'💵'},{l:'Positions',v:filtPos.length,i:'📊'},{l:'P&L',v:`${totalPnL>=0?'+':''}$${totalPnL.toFixed(2)}`,i:'💰',c:totalPnL>=0?'text-emerald-400':'text-red-400'},{l:'Forecasts',v:forecasts.length,i:'🔮'}].map(s=><div key={s.l} className="bg-zinc-900 border border-zinc-800 rounded-xl p-4"><div className="text-xl mb-1">{s.i}</div><div className={`text-xl font-bold ${s.c??'text-white'}`}>{s.v}</div><div className="text-xs text-zinc-500">{s.l}</div></div>)}</div>}
        {showPortForm&&<form onSubmit={createPort} className="bg-zinc-900 border border-violet-800/40 rounded-2xl p-6 space-y-3"><h3 className="font-semibold text-white text-sm">New Portfolio</h3><div className="grid grid-cols-3 gap-3"><input className={ic} placeholder="Name *" required value={form.pname||''} onChange={e=>setForm({...form,pname:e.target.value})}/><input className={ic} placeholder="Description" value={form.pdesc||''} onChange={e=>setForm({...form,pdesc:e.target.value})}/><input className={ic} placeholder="Starting cash ($)" type="number" value={form.cash||''} onChange={e=>setForm({...form,cash:e.target.value})}/></div><div className="flex gap-2"><button type="submit" className="bg-violet-600 hover:bg-violet-500 text-white text-sm px-4 py-2 rounded-lg">Create</button><button type="button" onClick={()=>setShowPortForm(false)} className="text-zinc-400 text-sm px-4 py-2 rounded-lg hover:bg-zinc-800">Cancel</button></div></form>}
        {showPosForm&&<form onSubmit={createPos} className="bg-zinc-900 border border-violet-800/40 rounded-2xl p-6 space-y-3"><h3 className="font-semibold text-white text-sm">Add Position</h3><div className="grid grid-cols-2 sm:grid-cols-5 gap-3"><input className={ic} placeholder="Symbol *" required value={form.sym||''} onChange={e=>setForm({...form,sym:e.target.value})}/><select className={ic} value={form.atype||'stock'} onChange={e=>setForm({...form,atype:e.target.value})}><option value="stock">Stock</option><option value="crypto">Crypto</option><option value="option">Option</option><option value="forex">Forex</option></select><input className={ic} placeholder="Qty *" type="number" step="any" required value={form.qty||''} onChange={e=>setForm({...form,qty:e.target.value})}/><input className={ic} placeholder="Avg cost *" type="number" step="any" required value={form.cost||''} onChange={e=>setForm({...form,cost:e.target.value})}/><input className={ic} placeholder="Current price" type="number" step="any" value={form.price||''} onChange={e=>setForm({...form,price:e.target.value})}/></div><div className="flex gap-2"><button type="submit" className="bg-violet-600 hover:bg-violet-500 text-white text-sm px-4 py-2 rounded-lg">Add</button><button type="button" onClick={()=>setShowPosForm(false)} className="text-zinc-400 text-sm px-4 py-2 rounded-lg hover:bg-zinc-800">Cancel</button></div></form>}
        {showFcForm&&<form onSubmit={createFc} className="bg-zinc-900 border border-emerald-800/40 rounded-2xl p-6 space-y-3"><h3 className="font-semibold text-white text-sm">New Forecast</h3><div className="grid grid-cols-2 sm:grid-cols-3 gap-3"><input className={ic} placeholder="Symbol *" required value={form.fsym||''} onChange={e=>setForm({...form,fsym:e.target.value})}/><input className={ic} placeholder="Target price *" type="number" step="any" required value={form.ftarget||''} onChange={e=>setForm({...form,ftarget:e.target.value})}/><input className={ic} type="date" required value={form.fdate||''} onChange={e=>setForm({...form,fdate:e.target.value})}/><input className={ic} placeholder="Confidence 0-100" type="number" value={form.fconf||''} onChange={e=>setForm({...form,fconf:e.target.value})}/><input className={ic} placeholder="Model (manual/TA/ML)" value={form.fmodel||''} onChange={e=>setForm({...form,fmodel:e.target.value})}/><input className={ic} placeholder="Notes" value={form.fnotes||''} onChange={e=>setForm({...form,fnotes:e.target.value})}/></div><div className="flex gap-2"><button type="submit" className="bg-emerald-600 hover:bg-emerald-500 text-white text-sm px-4 py-2 rounded-lg">Save</button><button type="button" onClick={()=>setShowFcForm(false)} className="text-zinc-400 text-sm px-4 py-2 rounded-lg hover:bg-zinc-800">Cancel</button></div></form>}
        <div className="flex gap-1 mb-2">{(['positions','forecasts']as const).map(t=><button key={t} onClick={()=>setTab(t)} className={`px-4 py-2 rounded-lg text-sm font-medium capitalize transition-all ${tab===t?'bg-zinc-800 text-white':'text-zinc-500 hover:text-white'}`}>{t} ({t==='positions'?filtPos.length:forecasts.length})</button>)}</div>
        {loading?<div className="text-center py-16 text-zinc-500">Loading…</div>:tab==='positions'?(
          filtPos.length===0?<div className="text-center py-16 text-zinc-500">No positions. Add one above.</div>:
          <div className="space-y-2">{filtPos.map((p:any)=>{const pnl=Number(p.pnl);const pct=Number(p.avg_cost)>0?((Number(p.current_price)-Number(p.avg_cost))/Number(p.avg_cost)*100):0;return(<div key={p.id} className="bg-zinc-900 border border-zinc-800 hover:border-zinc-700 rounded-xl px-5 py-4 flex items-center gap-4 transition-all"><div className="w-10 h-10 rounded-lg bg-zinc-800 flex items-center justify-center font-mono font-bold text-xs text-zinc-300 flex-shrink-0">{p.symbol?.slice(0,4)}</div><div className="flex-1 min-w-0"><div className="flex items-center gap-2"><span className="font-bold text-white text-sm">{p.symbol}</span><span className={`text-xs px-2 py-0.5 rounded-md ${AC[p.asset_type]??''}`}>{p.asset_type}</span></div><p className="text-xs text-zinc-500">{Number(p.quantity).toLocaleString()} @ ${Number(p.avg_cost).toFixed(2)}</p></div><div className="text-right"><div className="font-mono text-sm text-white">${Number(p.current_price).toFixed(2)}</div><div className={`font-mono text-xs ${pnl>=0?'text-emerald-400':'text-red-400'}`}>{pnl>=0?'+':''}{pnl.toFixed(2)} ({pct>=0?'+':''}{pct.toFixed(1)}%)</div></div></div>)})}</div>
        ):(
          forecasts.length===0?<div className="text-center py-16 text-zinc-500">No forecasts. Add one above.</div>:
          <div className="space-y-2">{forecasts.map((fc:any)=><div key={fc.id} className="bg-zinc-900 border border-zinc-800 rounded-xl px-5 py-4 flex items-center gap-4"><div className="w-10 h-10 rounded-lg bg-emerald-900/30 flex items-center justify-center text-lg">🔮</div><div className="flex-1"><div className="font-bold text-white text-sm">{fc.symbol} → ${Number(fc.target_price).toFixed(2)}</div><p className="text-xs text-zinc-500">{fc.prediction_date} · {fc.model_used} · {fc.confidence_score}% confidence</p></div><span className={`text-xs px-2 py-1 rounded-md font-medium ${fc.outcome==='correct'?'bg-emerald-900/40 text-emerald-400':fc.outcome==='incorrect'?'bg-red-900/40 text-red-400':'bg-zinc-800 text-zinc-400'}`}>{fc.outcome??'pending'}</span></div>)}</div>
        )}
      </div>
    </div>
  )
}

