'use client'
import{useEffect,useState}from'react'
const TC2:Record<string,string>={manual:'bg-zinc-700 text-zinc-300',automation:'bg-blue-900/40 text-blue-400',webhook:'bg-amber-900/40 text-amber-400',scheduled:'bg-violet-900/40 text-violet-400'}
const SC:Record<string,string>={active:'bg-emerald-900/40 text-emerald-400',inactive:'bg-zinc-800 text-zinc-500',error:'bg-red-900/40 text-red-400'}
export default function CommandCenter(){
  const[cmds,setCmds]=useState<any[]>([])
  const[logs,setLogs]=useState<any[]>([])
  const[loading,setLoading]=useState(true)
  const[running,setRunning]=useState<string|null>(null)
  const[show,setShow]=useState(false)
  const[tab,setTab]=useState<'commands'|'logs'>('commands')
  const[form,setForm]=useState<Record<string,string>>({})
  const ic="w-full bg-zinc-800 border border-zinc-700 rounded-lg px-3 py-2 text-sm text-zinc-100 placeholder-zinc-500 focus:outline-none focus:ring-2 focus:ring-violet-500"
  async function load(){setLoading(true);const[c,l]=await Promise.all([fetch('/api/commands').then(r=>r.json()),fetch('/api/command-logs').then(r=>r.json())]);setCmds(c.data??[]);setLogs(l.data??[]);setLoading(false)}
  useEffect(()=>{load()},[])
  async function run(id:string){setRunning(id);await fetch(`/api/commands/${id}/run`,{method:'POST'});setRunning(null);load()}
  async function create(e:React.FormEvent){e.preventDefault();await fetch('/api/commands',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({title:form.title,description:form.desc,command_type:form.type||'manual',payload:{},status:'active'})});setShow(false);setForm({});load()}
  async function toggle(cmd:any){await fetch(`/api/commands/${cmd.id}`,{method:'PATCH',headers:{'Content-Type':'application/json'},body:JSON.stringify({status:cmd.status==='active'?'inactive':'active'})});load()}
  return(
    <div className="min-h-screen bg-zinc-950 text-zinc-100">
      <div className="sticky top-0 z-30 bg-zinc-900/80 backdrop-blur border-b border-zinc-800">
        <div className="max-w-5xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3"><a href="/dashboard" className="text-zinc-500 hover:text-white text-sm">← Hub</a><span className="text-zinc-700">|</span><span>⚙️</span><h1 className="font-bold text-white">Command Center</h1><span className="text-xs bg-zinc-800 text-zinc-400 px-2 py-0.5 rounded-full">{cmds.filter(c=>c.status==='active').length} active</span></div>
          <button onClick={()=>setShow(!show)} className="bg-violet-600 hover:bg-violet-500 text-white text-sm font-medium px-4 py-2 rounded-lg">+ Command</button>
        </div>
      </div>
      <div className="max-w-5xl mx-auto px-4 py-8 space-y-6">
        <div className="grid grid-cols-4 gap-4">{[{l:'Total',v:cmds.length,i:'⚙️'},{l:'Active',v:cmds.filter(c=>c.status==='active').length,i:'✅'},{l:'Runs',v:logs.length,i:'▶️'},{l:'Success',v:logs.length?`${Math.round(logs.filter(l=>l.status==='success').length/logs.length*100)}%`:'—',i:'📊'}].map(s=><div key={s.l} className="bg-zinc-900 border border-zinc-800 rounded-xl p-4"><div className="text-xl mb-1">{s.i}</div><div className="text-2xl font-bold text-white">{s.v}</div><div className="text-xs text-zinc-500">{s.l}</div></div>)}</div>
        {show&&<form onSubmit={create} className="bg-zinc-900 border border-violet-800/40 rounded-2xl p-6 space-y-3"><h3 className="font-semibold text-white text-sm">New Command</h3><div className="grid grid-cols-3 gap-3"><input className={ic} placeholder="Title *" required value={form.title||''} onChange={e=>setForm({...form,title:e.target.value})}/><input className={ic} placeholder="Description" value={form.desc||''} onChange={e=>setForm({...form,desc:e.target.value})}/><select className={ic} value={form.type||'manual'} onChange={e=>setForm({...form,type:e.target.value})}><option value="manual">Manual</option><option value="automation">Automation</option><option value="webhook">Webhook</option><option value="scheduled">Scheduled</option></select></div><div className="flex gap-2"><button type="submit" className="bg-violet-600 hover:bg-violet-500 text-white text-sm px-4 py-2 rounded-lg">Create</button><button type="button" onClick={()=>setShow(false)} className="text-zinc-400 text-sm px-4 py-2 rounded-lg hover:bg-zinc-800">Cancel</button></div></form>}
        <div className="flex gap-1">{(['commands','logs']as const).map(t=><button key={t} onClick={()=>setTab(t)} className={`px-4 py-2 rounded-lg text-sm font-medium capitalize transition-all ${tab===t?'bg-zinc-800 text-white':'text-zinc-500 hover:text-white'}`}>{t} ({t==='commands'?cmds.length:logs.length})</button>)}</div>
        {loading?<div className="text-center py-16 text-zinc-500">Loading…</div>:tab==='commands'?(
          cmds.length===0?<div className="text-center py-16 text-zinc-500">No commands yet.</div>:
          <div className="space-y-2">{cmds.map((cmd:any)=><div key={cmd.id} className="bg-zinc-900 border border-zinc-800 hover:border-zinc-700 rounded-xl px-5 py-4 flex items-center gap-4 group transition-all"><div className="w-10 h-10 rounded-lg bg-zinc-800 flex items-center justify-center text-lg flex-shrink-0">⚙️</div><div className="flex-1 min-w-0"><div className="flex items-center gap-2 flex-wrap"><span className="font-semibold text-zinc-100 text-sm">{cmd.title}</span><span className={`text-xs px-2 py-0.5 rounded-md ${TC2[cmd.command_type]}`}>{cmd.command_type}</span><span className={`text-xs px-2 py-0.5 rounded-md ${SC[cmd.status]}`}>{cmd.status}</span></div><p className="text-xs text-zinc-600 mt-0.5">Runs: {cmd.run_count} · Last: {cmd.last_run_at?new Date(cmd.last_run_at).toLocaleString():'Never'}</p></div><div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity"><button onClick={()=>toggle(cmd)} className="text-xs text-zinc-400 hover:text-white px-3 py-1.5 rounded-lg bg-zinc-800 hover:bg-zinc-700">{cmd.status==='active'?'Disable':'Enable'}</button><button onClick={()=>run(cmd.id)} disabled={running===cmd.id} className="text-xs bg-violet-600 hover:bg-violet-500 disabled:opacity-50 text-white px-3 py-1.5 rounded-lg">{running===cmd.id?'Running…':'▶ Run'}</button></div></div>)}</div>
        ):(
