  async function save(e:React.FormEvent){e.preventDefault();await fetch('/api/tracks',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(form)});setShow(false);setForm({});load()}
  async function del(id:string){await fetch(`/api/tracks/${id}`,{method:'DELETE'});load()}
