const SC:Record<string,string>={draft:'bg-zinc-700 text-zinc-300',published:'bg-emerald-900/50 text-emerald-400',archived:'bg-red-900/50 text-red-400'}

export default function MusicStudio(){
  const[tracks,setTracks]=useState<any[]>([])
  const[loading,setLoading]=useState(true)
  const[show,setShow]=useState(false)
  const[form,setForm]=useState<Record<string,string>>({})
  const[saving,setSaving]=useState(false)
  const[q,setQ]=useState('')

  async function load(){setLoading(true);const r=await fetch('/api/tracks').then(r=>r.json());setTracks(r.data??[]);setLoading(false)}
  useEffect(()=>{load()},[])

  async function add(e:React.FormEvent){
    e.preventDefault();setSaving(true)
    await fetch('/api/tracks',{method:'POST',headers:{'Content-Type':'application/json'},
      body:JSON.stringify({title:form.title,genre:form.genre||null,bpm:form.bpm?parseInt(form.bpm):null,status:'draft'})})
    setShow(false);setForm({});setSaving(false);load()
  }
  async function toggle(t:any){
    await fetch(`/api/tracks/${t.id}`,{method:'PATCH',headers:{'Content-Type':'application/json'},body:JSON.stringify({status:t.status==='draft'?'published':'draft'})});load()
  }
  async function del(id:string){await fetch(`/api/tracks/${id}`,{method:'DELETE'});load()}

  const ic="w-full bg-zinc-800 border border-zinc-700 rounded-lg px-3 py-2 text-sm text-zinc-100 placeholder-zinc-500 focus:outline-none focus:ring-2 focus:ring-violet-500"
  const filtered=tracks.filter(t=>t.title.toLowerCase().includes(q.toLowerCase()))

  return(
