          <button onClick={()=>setShow(!show)} className="bg-violet-600 hover:bg-violet-500 text-white text-sm font-medium px-4 py-2 rounded-lg transition-all">+ Track</button>
        </div>
      </div>
      <div className="max-w-5xl mx-auto px-4 py-8 space-y-6">
        <input value={q} onChange={e=>setQ(e.target.value)} className={ic} placeholder="Search tracks…"/>
        {show&&(
          <form onSubmit={add} className="bg-zinc-900 border border-violet-800/40 rounded-2xl p-6 space-y-4">
            <h3 className="font-semibold text-white text-sm">New Track</h3>
            <div className="grid grid-cols-3 gap-3">
              <input className={ic} placeholder="Title *" required value={form.title||''} onChange={e=>setForm({...form,title:e.target.value})}/>
              <input className={ic} placeholder="Genre" value={form.genre||''} onChange={e=>setForm({...form,genre:e.target.value})}/>
              <input className={ic} placeholder="BPM" type="number" value={form.bpm||''} onChange={e=>setForm({...form,bpm:e.target.value})}/>
            </div>
            <div className="flex gap-2">
              <button type="submit" disabled={saving} className="bg-violet-600 hover:bg-violet-500 disabled:opacity-50 text-white text-sm px-4 py-2 rounded-lg">{saving?'Saving…':'Save'}</button>
              <button type="button" onClick={()=>setShow(false)} className="text-zinc-400 text-sm px-4 py-2 rounded-lg hover:bg-zinc-800">Cancel</button>
            </div>
          </form>
        )}
        {loading?<div className="text-center py-16 text-zinc-500">Loading…</div>:filtered.length===0?<div className="text-center py-16"><div className="text-5xl mb-4">🎵</div><p className="text-zinc-500">No tracks yet — add one above</p></div>:(
          <div className="space-y-2">
            {filtered.map((t:any)=>(
              <div key={t.id} className="bg-zinc-900 border border-zinc-800 hover:border-zinc-700 rounded-xl px-5 py-4 flex items-center gap-4 group transition-all">
                <div className="w-10 h-10 rounded-lg bg-gradient-to-br from-violet-700 to-pink-700 flex items-center justify-center text-lg flex-shrink-0">🎵</div>
                <div className="flex-1 min-w-0">
                  <p className="font-medium text-zinc-100 truncate">{t.title}</p>
                  <p className="text-xs text-zinc-500 mt-0.5">{[t.genre,t.bpm?`${t.bpm} BPM`:null].filter(Boolean).join(' · ')||'No details'}</p>
                </div>
                <span className={`text-xs px-2 py-0.5 rounded-md font-medium ${SC[t.status]}`}>{t.status}</span>
                <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                  <button onClick={()=>toggle(t)} className="text-xs text-zinc-400 hover:text-violet-400 px-2 py-1 rounded hover:bg-zinc-800">{t.status==='draft'?'Publish':'Unpublish'}</button>
                  <button onClick={()=>del(t.id)} className="text-xs text-zinc-500 hover:text-red-400 px-2 py-1 rounded hover:bg-zinc-800">×</button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  )
}

